head.script:
scwin.memJson = {};
scwin.userId = "";
scwin.loginEmpNo = "";
scwin.paramData = {};

// 대표거래처 코드 
scwin.kcomcd = "";
// 해운 항공 구분 
scwin.seaair = "";
// Import / Export 구분
scwin.iogb = "";
// Master B/L No
scwin.mblno = "";
// Console No
scwin.mhno = "";
// House B/L No
scwin.blno = "";
// Invoice No
scwin.prtnGrpNo = "";
// 청구 거래처 코드
scwin.bilgClntNo = "";

scwin.processFlag = "";
scwin.E_MSG_ERR_001 = "전표번호가  (@) 존재 합니다. 수정 삭제 할 수 없습니다.";
scwin.tabGb = "";
scwin.originBillingDate = "";

scwin.moveOpenMenu = "";
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // console.log($c.data.getMemInfo());
    // console.log($c.data.getParameter());

    scwin.memJson   = $c.data.getMemInfo();
    scwin.paramData = $c.data.getParameter();

    if (!scwin.paramData) {
        scwin.paramData = {
            "kcomcd": "DBEX",
            "seaair": "S",
            "iogb": "O",
            "mblno": "",
            "mhno": "",
            "blno": "",
            "prtnGrpNo": "",
            "bilgClntNo": ""
        };
    }

    scwin.userId        = scwin.memJson.userId;
    scwin.loginEmpNo    = scwin.memJson.userId          == null ? ""    : scwin.memJson.empNo;
    scwin.kcomcd        = scwin.paramData.kcomcd        == null ? "DBEX" : scwin.paramData.kcomcd;
    scwin.seaair        = scwin.paramData.seaair        == null ? "S"   : scwin.paramData.seaair;
    scwin.iogb          = scwin.paramData.iogb          == null ? "O"   : scwin.paramData.iogb;
    scwin.mblno         = scwin.paramData.mblno         == null ? ""    : scwin.paramData.mblno;
    scwin.mhno          = scwin.paramData.mhno          == null ? ""    : scwin.paramData.mhno;
    scwin.blno          = scwin.paramData.blno          == null ? ""    : scwin.paramData.blno;
    scwin.prtnGrpNo     = scwin.paramData.prtnGrpNo     == null ? ""    : scwin.paramData.prtnGrpNo;
    scwin.bilgClntNo    = scwin.paramData.bilgClntNo    == null ? ""    : scwin.paramData.bilgClntNo;
    scwin.moveOpenMenu  = scwin.paramData.moveOpenMenu  == null ? ""    : scwin.paramData.moveOpenMenu;

    scwin.f_DefaultValue();
    scwin.processFlag = "INIT";
    chb_pre.setSelectedIndex(0);
    scwin.f_Set("INIT");

    if (!$c.util.isEmpty(scwin.blno)) {
        $c.util.setTimeout(() => {
            scwin.f_Retrieve();
            ed_bilgPicNo.setReadOnly(true);
            txt_bilgPicNm.setReadOnly(true);
            img_bilgPicNo.setDisabled(true);
        }, { delay: 400 })
    } else if ($c.util.isEmpty(scwin.mblno)) {
        $c.util.setTimeout(() => {
            ed_bilgPicNo.setReadOnly(true);
            txt_bilgPicNm.setReadOnly(true);
            img_bilgPicNo.setDisabled(true);
        }, { delay: 400 })
    } else {
        $c.util.setTimeout(() => {
            ed_bilgPicNo.setReadOnly(true);
            txt_bilgPicNm.setReadOnly(true);
            img_bilgPicNo.setDisabled(true);
        }, { delay: 400 })
    }

    $c.util.setTimeout(() => {
        $c.data.setPopupTitle("Partner Invoice");
    }, { delay: 200 })
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () { 
    wfm_header.getWindow().scwin.setTitle("Partner Invoice"); 
    $p.top().tac_layout.setLabelText($p.top().tac_layout.getSelectedTabIndex(), "Partner Invoice")
}


//-------------------------------------------------------------------------
// 휴지통 처리
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_retrieve, null);
    dlt_ConsoleNo.removeAll();
}

//-------------------------------------------------------------------------
// function name : f_DefaultValue
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    dma_searchFreight.set("locPtnCls", "2")  //국내해외매출구분(국내:1 해외:2)
    dma_search.set("kcomcd", scwin.kcomcd);
    dma_search.set("seaair", scwin.seaair);
    dma_search.set("iogb", scwin.iogb);
    dma_search.set("mblno", scwin.mblno);
    dma_search.set("blno", scwin.blno);
    dma_search.set("prtnGrpNo", scwin.prtnGrpNo);
    dma_search.set("bilgClntNo", scwin.bilgClntNo);

    if (dma_search.get("mblno") != "") {
        scwin.f_MhnoLoading("M", dma_search.get("mblno"));
    }

    if (dma_search.get("blno") != "") {
        scwin.f_MhnoLoading("H", dma_search.get("blno"));
    }

    dma_search.set("mhno", scwin.mhno);

}

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    let gubunVal = gubun;
    // console.log("scwin.f_Set : " + gubunVal + " : " + scwin.processFlag);

    switch (gubun) {

        case "INIT": //초기화
            $c.gus.cfDisableBtnOnly([btn_Print, btn_Print_N, btn_Create, btn_Update, btn_Cancel, btn_Save, btn_Delete]);
            break;

        case "RETRIEVE":  //조회모드

// console.log("scwin.processFlag RETRIEVE : " + scwin.processFlag)
            if (scwin.processFlag == "RETRIEVE") {
                $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
                $c.gus.cfEnableBtnOnly([btn_Update, btn_Delete, btn_Print, btn_Print_N]);
            } else {
                $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_Print, btn_Print_N]);
                $c.gus.cfEnableBtnOnly([btn_Create]);
            }

            scwin.f_FormEnableChange(true);
            break;
        case "CANCEL":	//취소
            scwin.f_Set("RETRIEVE");
            break;
        case "CREATE": //신규   
            scwin.processFlag = "CREATE";
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);
            dlt_partnerInvoiceList.setCellData(dlt_partnerInvoiceList.getRowPosition(), "intendDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
            dlt_invoiceCommon.setCellData(0, "confirmDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
            dlt_invoiceCommon.setCellData(0, "bilgIntendDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));
            dlt_purchaseCerti.setCellData(0, "pchsIntendDt", $p.getFormattedDate(new Date(), "yyyyMMdd"));

            scwin.f_FormEnableChange(false);

            // $c.gus.cfEnableObjects([ed_bilgIntendDt, ed_clntBilgDocNo, ed_bilgPicNo, bilgPicNm, txt_bilgPicNm]);
            ed_bilgIntendDt.focus();
            break;
        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);

            scwin.f_FormEnableChange(false);
            ed_bilgIntendDt.focus();

            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
        case "DELETE":
            cfDisableBtnOnly([btn_Save, btn_Cancel]);
            cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_FormEnableChange = function( flag ) {

    ed_bilgIntendDt.setReadOnly(flag);
    ed_clntBilgDocNo.setReadOnly(flag);
    ed_bilgPicNo.setReadOnly(flag);
    img_bilgPicNo.setDisabled(flag);
    txt_bilgPicNm.setReadOnly(flag);    
}

//MHNNO 가져오기
scwin.f_MhnoLoading = function (mhgb, blno) {
    let strClntNo = "";
    strClntNo = blno;

    if (strClntNo.length > 0) {
        param1 = strClntNo;

        if (cnd_lc_seaair.getValue() == "A") {
            if (mhgb == "M") {
                let submissionObj = {};
                submissionObj.id = "sbm_Console_No";
                submissionObj.target = 'data:json,[{"id":"dlt_ConsoleNo","action":"all", "key": "GAUCE"}]';
                submissionObj.action = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveAirMasterMhnoListCombo&param1=" + param1 + "&param2=" + cnd_lc_iogb.getValue();
                submissionObj.method = "post";
                submissionObj.mediatype = "application/json";
                submissionObj.encoding = "UTF-8";
                submissionObj.submitDoneHandler = async function (e) {
                    if (dlt_ConsoleNo.getRowCount() == 0) {
                        await $c.win.alert("Data not found.");
                    } else {
                        if(scwin.mblno != '' || scwin.blno != ''){
                            scwin.btn_retrieve_onclick();
                        }
                    }
                }
                $c.sbm.executeDynamic(submissionObj);

            } else {
                let submissionObj = {};
                submissionObj.id = "sbm_Console_No";
                submissionObj.target = 'data:json,[{"id":"dlt_ConsoleNo","action":"all", "key": "GAUCE"}]';
                submissionObj.action = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveAirHouseMhnoListCombo&param1=" + param1 + "&param2=" + cnd_lc_iogb.getValue();
                submissionObj.method = "post";
                submissionObj.mediatype = "application/json";
                submissionObj.encoding = "UTF-8";
                submissionObj.submitDoneHandler = async function (e) {
                    if (dlt_ConsoleNo.getRowCount() == 0) {
                        await $c.win.alert("Data not found.");
                    } else {
                        if(scwin.mblno != '' || scwin.blno != ''){
                            scwin.btn_retrieve_onclick();
                        }
                    }
                }
                $c.sbm.executeDynamic(submissionObj);
            }
        } else {

            if (mhgb == "M") {
                //ds_mhno.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveSeaMasterMhnoListCombo&param1=" + param1 + "&param2=" + cnd_lc_iogb.BindColVal;
                let submissionObj = {};
                submissionObj.id = "sbm_Console_No";
                submissionObj.target = 'data:json,[{"id":"dlt_ConsoleNo","action":"all", "key": "GAUCE"}]';
                submissionObj.action = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveSeaMasterMhnoListCombo&param1=" + param1 + "&param2=" + cnd_lc_iogb.getValue();
                submissionObj.method = "post";
                submissionObj.mediatype = "application/json";
                submissionObj.encoding = "UTF-8";
                submissionObj.submitDoneHandler = async function (e) {
                    if (dlt_ConsoleNo.getRowCount() == 0) {
                        await $c.win.alert("Data not found.");
                    } else {
                        if(scwin.mblno != '' || scwin.blno != ''){
                            scwin.btn_retrieve_onclick();
                        }
                    }
                }
                $c.sbm.executeDynamic(submissionObj);

            } else {
                //ds_mhno.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveSeaHouseMhnoListCombo&param1=" + param1 + "&param2=" + cnd_lc_iogb.BindColVal;
                let submissionObj = {};
                submissionObj.id = "sbm_Console_No";
                submissionObj.target = 'data:json,[{"id":"dlt_ConsoleNo","action":"all", "key": "GAUCE"}]';
                submissionObj.action = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveSeaHouseMhnoListCombo&param1=" + param1 + "&param2=" + cnd_lc_iogb.getValue();
                submissionObj.method = "post";
                submissionObj.mediatype = "application/json";
                submissionObj.encoding = "UTF-8";
                submissionObj.submitDoneHandler = async function (e) {
                    if (dlt_ConsoleNo.getRowCount() == 0) {
                        await $c.win.alert("Data not found.");
                    } else {
                        if(scwin.mblno != '' || scwin.blno != ''){
                            scwin.btn_retrieve_onclick();
                        }
                    }
                }

                $c.sbm.executeDynamic(submissionObj);

            }
        }
        //ds_mhno.Reset();
    }
};

//조회
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
}

scwin.f_Retrieve = function(){
    dlt_partnerFreight.removeAll();

    if ($c.util.isEmpty(cnd_ed_mblno.getValue()) && $c.util.isEmpty(cnd_ed_blno.getValue())) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("Master or House B/L"));
        cnd_ed_mblno.focus();
        return;
    }

    // Console No 체크
    if ($c.util.isEmpty(cnd_lc_mhno.getValue())) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("Console No"));
        return;
    }

    //dataset clear
    dlt_partnerInvoiceList.removeAll();
    dlt_invoiceCommon.removeAll();
    dlt_purchaseCerti.removeAll();
    dlt_partnerFreight.removeAll();

    $c.sbm.execute(sbm_retrieve);
};

//조회 콜백
scwin.sbm_retrieve_submitdone = async function (e) {

    let rowCount = dlt_partnerInvoiceList.getRowCount();

    if (rowCount == 0) {
        $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.processFlag = "INIT";
        scwin.f_Set("INIT");
    } else {
        dlt_partnerInvoiceList.setRowPosition(0);
        totalTxt.setValue(rowCount);
    }
};

scwin.dlt_partnerInvoiceList_onrowpositionchange = function (info) {
    // console.log(info);

    var rowIndex = info.newRowIndex;

    var tmp_slipNo = '';

    if(rowIndex == null)
        return;

    var vCountRow = dlt_partnerInvoiceList.getRowCount();
    for(var i=0;i<=vCountRow;i++){
        tmp_slipNo = dlt_partnerInvoiceList.getCellData(i,"slipNo");
    }

    var prtnGrpNo = dlt_partnerInvoiceList.getCellData(rowIndex, "prtnGrpNo"); // 거래명세서Group번호

    dma_searchFreight.set("kcomcd"      , dlt_partnerInvoiceList.getCellData(rowIndex, "kcomcd")); 	// 대표 거래처 코드
    dma_searchFreight.set("seaair"      , dlt_partnerInvoiceList.getCellData(rowIndex, "seaair")); 	// 해운 항공 Trans 구분
    dma_searchFreight.set("iogb"        , dlt_partnerInvoiceList.getCellData(rowIndex, "iogb")); 		// Import/Export 구분
    dma_searchFreight.set("mblno"       , dlt_partnerInvoiceList.getCellData(rowIndex, "mblno")); 		// MASTER B/L NO 
    dma_searchFreight.set("blno"        , dlt_partnerInvoiceList.getCellData(rowIndex, "blno")); 		// HOUSE B/L NO

    dma_searchFreight.set("mhno"        , dlt_partnerInvoiceList.getCellData(rowIndex, "mhno"));

    dma_searchFreight.set("prtnGrpNo"   , dlt_partnerInvoiceList.getCellData(rowIndex, "prtnGrpNo")); // 거래명세서Group번호
    dma_searchFreight.set("bilgClntNo"  , dlt_partnerInvoiceList.getCellData(rowIndex, "bilgClntNo")); 	// 청구처 코드 
    dma_searchFreight.set("bilgClntNm"  , dlt_partnerInvoiceList.getCellData(rowIndex, "bilgClntNm")); // 청구처명
    dma_searchFreight.set("odrNo"       , dlt_partnerInvoiceList.getCellData(rowIndex, "odrNo"));		// Order No
    dma_searchFreight.set("slipNo"      , dlt_partnerInvoiceList.getCellData(rowIndex, "slipNo")); 	// 전표번호
    dma_searchFreight.set("certiNo"     , dlt_partnerInvoiceList.getCellData(rowIndex, "certiNo"));	// 전표번호

    if(tmp_slipNo==""){
        $c.gus.cfDisableBtnOnly([btn_Print,btn_Print_N,btn_Create,btn_Update,btn_Cancel,btn_Save,btn_Delete]);
        if(prtnGrpNo.trim() ==""){
            $c.gus.cfEnableBtnOnly([btn_Create]);
            scwin.processFlag = "INIT";
        }else{
            $c.gus.cfEnableBtnOnly([btn_Print,btn_Print_N, btn_Update, btn_Delete]);
            scwin.processFlag = "RETRIEVE";
        }
    }else{
        $c.gus.cfDisableBtnOnly([btn_Print,btn_Print_N,btn_Create,btn_Update,btn_Cancel,btn_Save,btn_Delete]);
        if(prtnGrpNo.trim() ==""){
            $c.gus.cfEnableBtnOnly([btn_Create]);
            scwin.processFlag = "INIT";
        }else{
            $c.gus.cfEnableBtnOnly([btn_Create,btn_Update,btn_Print,btn_Print_N]);
            scwin.processFlag = "RETRIEVE";
        }
    }
};


// 그리드 클릭 
scwin.gr_partnerInvoiceList_oncellclick = function (rowIndex, columnIndex, columnId) {

    dma_searchFreight.set("kcomcd"      , dlt_partnerInvoiceList.getCellData(rowIndex, "kcomcd")); 	// 대표 거래처 코드
    dma_searchFreight.set("seaair"      , dlt_partnerInvoiceList.getCellData(rowIndex, "seaair")); 	// 해운 항공 Trans 구분
    dma_searchFreight.set("iogb"        , dlt_partnerInvoiceList.getCellData(rowIndex, "iogb")); 		// Import/Export 구분
    dma_searchFreight.set("mblno"       , dlt_partnerInvoiceList.getCellData(rowIndex, "mblno")); 		// MASTER B/L NO 
    dma_searchFreight.set("blno"        , dlt_partnerInvoiceList.getCellData(rowIndex, "blno")); 		// HOUSE B/L NO

    dma_searchFreight.set("mhno"        , dlt_partnerInvoiceList.getCellData(rowIndex, "mhno"));

    dma_searchFreight.set("prtnGrpNo"   , dlt_partnerInvoiceList.getCellData(rowIndex, "prtnGrpNo")); // 거래명세서Group번호
    dma_searchFreight.set("bilgClntNo"  , dlt_partnerInvoiceList.getCellData(rowIndex, "bilgClntNo")); 	// 청구처 코드 
    dma_searchFreight.set("bilgClntNm"  , dlt_partnerInvoiceList.getCellData(rowIndex, "bilgClntNm")); // 청구처명
    dma_searchFreight.set("odrNo"       , dlt_partnerInvoiceList.getCellData(rowIndex, "odrNo"));		// Order No
    dma_searchFreight.set("slipNo"      , dlt_partnerInvoiceList.getCellData(rowIndex, "slipNo")); 	// 전표번호
    dma_searchFreight.set("certiNo"     , dlt_partnerInvoiceList.getCellData(rowIndex, "certiNo"));	// 전표번호

    scwin.originBillingDate = dlt_partnerInvoiceList.getCellData(rowIndex, "intendDt");

    if ((dlt_partnerInvoiceList.getCellData(rowIndex, "blno") != "" 
            || dlt_partnerInvoiceList.getCellData(rowIndex, "mblno") != "") 
        && dlt_partnerInvoiceList.getCellData(rowIndex, "bilgClntNo") != "") {

        scwin.f_RetrieveCommon();
    }

    if (dlt_partnerInvoiceList.getCellData(rowIndex, "slipNo") == "" 
            && dlt_partnerInvoiceList.getCellData(rowIndex, "prtnGrpNo") != "") {

        $c.gus.cfEnableBtnOnly([btn_Delete]);

    } else {

        $c.gus.cfDisableBtnOnly([btn_Delete]);
    }
};

scwin.f_RetrieveCommon = function () {

    dlt_invoiceCommon.removeAll();
    dlt_purchaseCerti.removeAll();
    dlt_purchaseCerti.removeAll();

    $c.sbm.execute(sbm_revrieveCommon);

}

//sbm_revrieveCommon 콜백
scwin.sbm_revrieveCommon_submitdone = function (e) {

    // console.log(dlt_invoiceCommon.getRowCount());
    // console.log(dlt_purchaseCerti.getRowCount());
    totalTxt2.setValue(dlt_partnerFreight.getRowCount());
    let invoiceRowcnt = dlt_invoiceCommon.getRowCount();
    let purchaseRowcnt = dlt_purchaseCerti.getRowCount();
    let rowIdx = gr_partnerInvoiceList.getFocusedRowIndex();
    let realIdx = gr_partnerInvoiceList.getRealRowIndex(rowIdx);
    let rowIndex = dlt_partnerInvoiceList.getRowPosition();
    // console.log("invoiceRowcnt = " + invoiceRowcnt);
    // console.log("purchaseRowcnt = " + purchaseRowcnt);
    // console.log(rowIdx, realIdx);

    if (invoiceRowcnt != 0) {
        if (dlt_partnerInvoiceList.getCellData(rowIndex, "slipNo") == dlt_invoiceCommon.getCellData(0, "slipNo")) {
            dlt_partnerInvoiceList.setCellData(rowIndex, "debitAmt", dlt_invoiceCommon.getCellData(0, "spplyAmt"));
            dlt_partnerInvoiceList.setCellData(rowIndex, "debitAmtFcrc", dlt_invoiceCommon.getCellData(0, "spplyAmtFcrc"));
            //alert(ds_invoiceCommon.NameValue(1,"spplyAmt"));
            //default 모두 check

            dlt_invoiceCommon.setCellData(0, "taxnClsCd", "03");
            if (dlt_invoiceCommon.getCellData(0, "chk") == "F") {
                dlt_invoiceCommon.setCellData(0, "chk", "T");
            }
        }

        if(dlt_partnerInvoiceList.getRowStatus(rowIndex) != "R") {
            dlt_invoiceCommon.setCellData(0, "confirmDt", dlt_partnerInvoiceList.getCellData(rowIndex, "intendDt"));
            dlt_invoiceCommon.setCellData(0, "bilgIntendDt", dlt_partnerInvoiceList.getCellData(rowIndex, "intendDt"));
        }
    }

    if (purchaseRowcnt != 0) {
        if (dlt_partnerInvoiceList.getCellData(realIdx, "slipNo") == dlt_purchaseCerti.getCellData(0, "slipNo")) {
            // console.log("빛안")
            dlt_partnerInvoiceList.setCellData(realIdx, "creditAmt", dlt_purchaseCerti.getCellData(0, "pchsAmt"));
            dlt_partnerInvoiceList.setCellData(realIdx, "creditAmtFcrc", dlt_purchaseCerti.getCellData(0, "pchsAmtFcrc"));
            //default 모두 check

            if (dlt_purchaseCerti.getCellData(0, "chk") == "F") {
                dlt_purchaseCerti.setCellData(0, "chk", "T");
            }
        }

        if(dlt_partnerInvoiceList.getRowStatus(rowIndex) != "R") {
            dlt_purchaseCerti.setCellData(0, "pchsIntendDt", dlt_partnerInvoiceList.getCellData(rowIndex, "intendDt"));
        }
    }

    for (let i = 0; i < dlt_partnerFreight.getRowCount(); i++) {
        dlt_partnerFreight.setCellData(i, "seq", i + 1);
        dlt_partnerFreight.setCellData(i, "chk", "T");
    }
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

// Master B/L No 블러 이벤트
scwin.cnd_ed_mblno_onblur = function (e) {
    scwin.f_MhnoLoading("M", cnd_ed_mblno.getValue().trim());
};

