scwin.gr_invoiceFreightList_oncellclick = function (rowIndex, columnIndex, columnId) {

};

scwin.gr_invoiceFreightList_onheaderclick = function (headerId) {

    if(headerId == "headerCheck") {

        let isChecked = gr_invoiceFreightList.getHeaderValue(headerId);
        var certiNo = dlt_partnerInvoiceList.getCellData(dlt_partnerInvoiceList.getRowPosition(), "certiNo");
        let rowCnt = dlt_partnerFreight.getRowCount();

        if(certiNo != '') {
            if (isChecked) {
                for (let i = 0; i < rowCnt; i++) {
                    dlt_partnerFreight.setCellData(i, "chk", "T")
                    gr_invoiceFreightList.setCellChecked(i, 1, false);
                }
            } else {
                for (let i = 0; i < rowCnt; i++) {
                    dlt_partnerFreight.setCellData(i, "chk", "F")
                    gr_invoiceFreightList.setCellChecked(i, 1, true);
                }
            }
        }
    }
};



