//-------------------------------------------------------------------------
// 오즈화면
//-------------------------------------------------------------------------
scwin.f_Print = function (Gubun) {

    if (chb_pre.getValue() == "T" && chb_directSave.getValue() == "T") {
        $c.win.alert("미리보기 와 바로저장을 동시에 체크할 수 없습니다.");
        chb_directSave.checkAll(false);
        return false;
    }

    let reportFile = "";
    let odiName = "";
    let mode = "";

    if (Gubun == "N") {
        reportFile = "/il/acc/ac_104_01_01_01.ozr";
        odiName = "ac_104_01_01";
    } else {
        reportFile = "/il/acc/ac_104_01_01.ozr";
        odiName = "ac_104_01_01";
    }

// debugger;
    gr_partnerInvoiceList.focus();
    var rowIndex = dlt_partnerInvoiceList.getRowPosition();
    let odiParam = {
        "KCOMCD": dlt_partnerInvoiceList.getCellData(rowIndex, "kcomcd"),
        "PRTN_GRP_NO": dlt_partnerInvoiceList.getCellData(rowIndex, "prtnGrpNo"),
        "SEAAIR": dlt_partnerInvoiceList.getCellData(rowIndex, "seaair"),
        "IOGB": dlt_partnerInvoiceList.getCellData(rowIndex, "iogb"),
        "BILG_CLNT_NO": dlt_partnerInvoiceList.getCellData(rowIndex, "bilgClntNo"),
        "USER_ID": dlt_partnerInvoiceList.getCellData(rowIndex, "modId"),
        "TYPE": lc_printOp.getValue(),
        "EMP_NO": scwin.loginEmpNo
    }

    if (ed_bilgPicNo.getValue() != "") {
        odiParam.PIC = "1";		//담당자 있다
    } else {
        odiParam.PIC = "2";		//담당자 없다
    }

    var vMode = "";
    if (chb_pre.getValue() == "T") {
        vMode = "preview";
    } 

    if (chb_directSave.getValue() == "T") {
        vMode = "print";
    }

    let viewerParam = {
            "useprogressbar" : "false",
            "mode" :vMode,
            printcommand : true,
            zoom : 100, // 배율 설정
        };


// console.log(odiParam);
    let data = {
        odiName: odiName,
        reportName: reportFile,
        odiParam: odiParam,
        viewerParam: viewerParam,
        formParam: {
        }
    };

    var ozFileName = dlt_partnerInvoiceList.getCellData(rowIndex, "blno") + "_INVOICE_" + dlt_partnerInvoiceList.getCellData(rowIndex, "prtnGrpNo");
    let ozOptions = {
        type:'viewer', // viewer, print, download
        printMode:'view', // silent, view
        exportMode:'view', // silent, view
        exportFilename:ozFileName,
        exportPath:'C:\\OZExport',
        exportFormat:'pdf'
    }

    if (chb_pre.getValue() == "T") {
        $c.ext.openOzReport(data, ozOptions);
    } 

    if (chb_directSave.getValue() == "T") {
        $c.ext.downloadOzReport(data, ozOptions);
    }
}


