//  세금계산서 생성 팝업
//-------------------------------------------------------------------------  
scwin.f_SlipPopUp = async function () {
    if(dlt_invoiceCommon.getRowCount() == 0)
        return;

    if (dlt_invoiceCommon.getCellData(0, "chk") == "T") {
        if (dlt_invoiceCommon.getCellData(0, "prtnGrpNo") != "") {
            let data = {
                blno: dlt_partnerInvoiceList.getCellData(0, "blno"),
                intendDt: ed_bilgIntendDt.getValue().trim(),
                kcomcd: dlt_partnerInvoiceList.getCellData(0, "kcomcd"),
                prtnGrpNo: dlt_partnerInvoiceList.getCellData(0, "prtnGrpNo"),
                seaair: dlt_partnerInvoiceList.getCellData(0, "seaair"),
                iogb: dlt_partnerInvoiceList.getCellData(0, "iogb"),
                bilgClntNo: dlt_partnerInvoiceList.getCellData(0, "bilgClntNo"),
                userId: dlt_partnerInvoiceList.getCellData(0, "modId"),
                type: lc_printOp.getValue(),
                rmk: "",
                remark: "",
                eng: "",
                locPtnCls: "2",
                ds_certiCommon : dlt_invoiceCommon,
            }
            if (ed_bilgPicNo.getValue() != "") {
                data["pic"] = 1;
            } else {
                data["pic"] = 2;
            }

            //let rowData = dlt_invoiceCommon.getRowJSON(0);
            //dma_certiCommonDs.setJSON(rowData);

            //Radio Value	- 청구/영수
            //dma_certiCommonDs.set("receptClsCd", "02");
            //let dataObj = dma_certiCommonDs.getJSON();

            let opts = {
                id: "fs_202_06_03p",
                popupName: "영수 세금계산서 생성",
                modal: true,
                type: "browserPopup",
                title: "영수 세금계산서 생성",
                width: 850,
                height: 800
            }

            // console.log(data);
            await $c.win.openPopup("/ui/ds/fs/bilg/fs_202_06_03p.xml", opts, data);
            // let returnValue = window.showModalDialog(strPath, pram, style);

            // if (returnValue[0] != undefined) {
            //     dtl_sellVatNo.value = returnValue[0];
            // }
            // if (returnValue[1] == "TRUE") {
            //     f_Retrieve();
            // }
        }
    } else {
        //cfAlertMsg(MSG_FS_WRN_002);
        $c.win.alert("세금계산서 호출조건이 안맞아서 실패");
    }
}

