// 세금계산서일괄생성 이동
//-------------------------------------------------------------------------  
scwin.f_SlipCreate = function (gbun) {
    // console.log("scwin.f_SlipCreate : " + gbun)
    if (gbun == "I") {

        let rowJSON = {
            bilgLodeptCd: (ed_dept.getValue() || "").trim(),
            bilgLodeptNm: (txt_deptnm.getValue() || "").trim(),
            bilgClntNo: (ed_bilgClntNo.getValue() || "").trim(),
            bilgClntNm: (txt_bilgClntNm.getValue() || "").trim(),
            certiPatternCd: "04",
            qryConDtFm: (ed_bilgIntendDt.getValue() || "").trim(),
            qryConDtTo: (ed_bilgIntendDt.getValue() || "").trim(),
            taxnClsCd: "03",
            kcomcd: dlt_partnerInvoiceList.getCellData(0, "kcomcd"),
            seaair: dlt_partnerInvoiceList.getCellData(0, "seaair"),
            iogb: dlt_partnerInvoiceList.getCellData(0, "iogb"),
            userId: dlt_partnerInvoiceList.getCellData(0, "modId"),
            type: lc_printOp.getValue(),
            rmk: "",
            eng: "",
            locPtnCls: "2"
        }
        if (ed_bilgPicNo.getValue() != "") {
            rowJSON["pic"] = 1;
        } else {
            rowJSON["pic"] = 2;
        }
        let options = {
            "openAction": "exist"
        }

        $c.win.openMenu("청구세금계산서일괄생성", "/ui/ds/fs/bilg/fs_202_06_05b.xml", "fs_202_06_05b.xml", rowJSON, options);

    } else {
        let rowJSON2 = {
            pchsDeptCd: (ed_dept.getValue() || "").trim(),
            pchsDeptNm: (txt_deptnm.getValue() || "").trim(),
            pchsClntNo: (ed_bilgClntNo.getValue() || "").trim(),
            pchsClntNm: (txt_bilgClntNm.getValue() || "").trim(),
            pchsIntendDtSt: (ed_bilgIntendDt.getValue() || "").trim(),
            pchsIntendDtEnd: (ed_bilgIntendDt.getValue() || "").trim(),
            partner : "P"

        }
        if (dlt_partnerFreight.getRowCount() > 0) {
            rowJSON2["certiNo"] = dlt_partnerFreight.getCellData(0, "certiNo");
        }
        let options2 = {
            "openAction": "exist"
        }
