//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    if (dlt_partnerInvoiceList.getCellData(dlt_partnerInvoiceList.getRowPosition(), "slipNo") != "") {
        let slipNo = dlt_partnerInvoiceList.getCellData(dlt_partnerInvoiceList.getRowPosition(), "slipNo");
        await $c.win.alert(`전표번호가 (${slipNo}) 존재 합니다. 수정 삭제 할 수 없습니다.`);
        return;
    }

    if (dlt_invoiceCommon.getRowCount() < 1 && dlt_purchaseCerti.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Partner Invoice"]); //var MSG_CM_ERR_056   =  "선택된 @이(가) 없습니다.";
        //$c.win.alert("선택된 Partner Invoice이(가) 없습니다.");
        return false;
    }

    if(dlt_partnerFreight.getRowCount() < 1){
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, new Array("Partner Invoice")); //@는 변경된 사항이 없습니다.
        return false;
    }

    let modifiedList = dlt_invoiceCommon.getModifiedIndex().length;
    let modifiedList2 = dlt_purchaseCerti.getModifiedIndex().length;
    let modifiedList3 = dlt_partnerFreight.getModifiedIndex().length;
    if (modifiedList.length == 0 && modifiedList2 == 0 && modifiedList3 == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, new Array("Partner Invoice")); //@는 변경된 사항이 없습니다.
        //$c.win.alert("Partner Invoice는 변경된 사항이 없습니다."); //@는 변경된 사항이 없습니다.
        return false;
    }

    let cur = "";
    let count = 0;
    let checkedPchsAmtSum = 0;
    let checkedPchsAmtFcrcSum = 0;

    let checkedSellAmtSum = 0; //매출 값 계산 위해 추가
    let checkedSellAmtFcrcSum = 0;

    // logic 추가, fs450의 pchs_amt 가 맞지 않 20100428
    for (let i = 0; i < dlt_partnerFreight.getRowCount(); i++) {
        if (dlt_partnerFreight.getCellData(i, "chk") == "T") {

            if (dlt_partnerFreight.getCellData(i, "drcrCls") == "C") {//매입일때

                if (cur != "" && cur != dlt_partnerFreight.getCellData(i, "crcCd")) {
                    count++;
                }

                cur = dlt_partnerFreight.getCellData(i, "crcCd");

                checkedPchsAmtSum = parseFloat(checkedPchsAmtSum) + parseFloat(dlt_partnerFreight.getCellData(i, "pchsAmt"));
                checkedPchsAmtFcrcSum = parseFloat(checkedPchsAmtFcrcSum) + parseFloat(dlt_partnerFreight.getCellData(i, "pchsAmtFcrc"));

            } else {//매출일때		  			  	  
                checkedSellAmtSum = parseFloat(checkedSellAmtSum) + parseFloat(dlt_partnerFreight.getCellData(i, "pchsAmt"));
                checkedSellAmtFcrcSum = parseFloat(checkedSellAmtFcrcSum) + parseFloat(dlt_partnerFreight.getCellData(i, "pchsAmtFcrc"));
            }
        }
    }
    if (count > 0) {
        alert("Invoice는 환종별로 생성해 주세요.");
        return false;
    }

    if (dlt_purchaseCerti.getCellData(0, "pchsAmt") != checkedPchsAmtSum) {
        dlt_purchaseCerti.setCellData(0, "pchsAmt", checkedPchsAmtSum);
        dlt_purchaseCerti.setCellData(0, "pchsAmtFcrc", checkedPchsAmtFcrcSum);
    }
    if (dlt_invoiceCommon.getCellData(0, "spplyAmt") != checkedSellAmtSum) {
        dlt_invoiceCommon.setCellData(0, "spplyAmt", checkedSellAmtSum);
        dlt_invoiceCommon.setCellData(0, "spplyAmtFcrc", checkedSellAmtFcrcSum);
        dlt_invoiceCommon.setCellData(0, "fcrcBilgAmt", checkedSellAmtSum);
        dlt_invoiceCommon.setCellData(0, "bilgAmtFcrc", checkedSellAmtFcrcSum);
    }

    dlt_invoiceCommon.setCellData(0, "bilgClntNm", dlt_partnerInvoiceList.getCellData(0, "bilgClntNm").substring(0, 49));

    //-------------------------------------------------------------------------
    // 거래명세서 생성후 금액 수정시 : 합계 계산 로직
    //-------------------------------------------------------------------------
    if (dlt_partnerInvoiceList.getCellData(0, "certiNo") != "" && dlt_partnerFreight.getModifiedIndex().length > 0) {//인보이스 금액 업데이트일때

        let checkedSellAmtSum = 0;
        let checkedSellAmtFcrcSum = 0;

        // logic 추가, 매출 AMT 
        for (let i = 0; i < dlt_partnerFreight.getRowCount(); i++) {
            if (dlt_partnerFreight.getCellData(i, "chk") == "T") {
                checkedSellAmtSum = parseFloat(checkedSellAmtSum + dlt_partnerFreight.getCellData(i, "sellAmt"));
                checkedSellAmtFcrcSum = parseFloat(checkedSellAmtFcrcSum) + parseFloat(dlt_partnerFreight.getCellData(i, "sellAmtFcrc"));
            }
        }

        if (dlt_invoiceCommon.getCellData(0, "spplyAmt") != checkedSellAmtSum) { //매출 INVOICE FS210 수정		
            dlt_invoiceCommon.setCellData(0, spplyAmt, checkedSellAmtSum);
            dlt_invoiceCommon.setCellData(0, "spplyAmtFcrc", checkedSellAmtFcrcSum);
            dlt_invoiceCommon.setCellData(0, "fcrcBilgAmt", checkedSellAmtFcrcSum);
            dlt_invoiceCommon.setCellData(0, "bilgAmtFcrc", checkedSellAmtFcrcSum);
        }


        // 매출 AMT 
        for (let i = 0; i < dlt_partnerFreight.getRowCount(); i++) {
            if (dlt_partnerFreight.getCelldata(i, "chk") == "T") {
                dlt_partnerFreight.setCellData(i, "spplyAmt", dlt_partnerFreight.getCellData(i, "sellAmt"));
                dlt_partnerFreight.setCellData(i, "spplyAmtFcrc", dlt_partnerFreight.getCellData(i, "sellAmtFcrc"));
                dlt_partnerFreight.setCellData(i, "bilgInscrpAmtFcrc", dlt_partnerFreight.getCellData(i, "sellAmtFcrc"));
            }
        }
        // 매입 AMT FS450 값 입력
        dlt_purchaseCerti.setCellData(0, "pchsAmt", checkedSellAmtSum);
        dlt_purchaseCerti.setCellData(0, "pchsAmtFcrc", checkedSellAmtFcrcSum);
    }

    if (await scwin.f_ReqFieldChk()) {
        if (await $c.win.confirm(E_MSG_CM_CRM_001)==true) {
            await $c.sbm.execute(sbm_save);
            scwin.processFlag = "RETRIEVE";
            scwin.f_Set("RETRIEVE");
        }
    }
}

//-------------------------------------------------------------------------
// Validate check
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function () {
    let ret = await $c.gus.cfValidate([oDetailInfo]);
    if (ret == false) {
        return false;
    }
    return true;
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {

    if (dlt_partnerInvoiceList.getCellData(0, "slipNo") != "") {
        let slipNo = dlt_partnerInvoiceList.getCellData(0, "slipNo");
        //$c.gus.cfAlertMsg(MSG_ERR_001,  [slipNo]);
        $c.win.alert(`전표번호가 (${slipNo}) 존재 합니다. 수정 삭제 할 수 없습니다.`);
        return;
    }

    var cfmRslt = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (cfmRslt == true) {	//삭제하시겠습니까?
        for(var i = 0; i < dlt_invoiceCommon.getRowCount(); i++){
            if (dlt_invoiceCommon.getCellData(i, "chk") == "T") {
                dlt_invoiceCommon.deleteRow(i);
            }
        }

        for(i = 0; i < dlt_purchaseCerti.getRowCount(); i++){
            if (dlt_purchaseCerti.getCellData(i, "chk") == "T") {
                dlt_purchaseCerti.deleteRow(i);
            }
        }
        $c.sbm.execute(sbm_save);
    }

}


scwin.btn_Delete_onclick = function (e) {
    scwin.f_Delete();
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

