scwin.dlt_partnerInvoiceList_oncelldatachange = function (info) {
    // console.log(info);

    var columnId = info.colID + "";
    var rowIndex = info.rowIndex;
    var value = info.newValue;

    //Billing Date (bilgIntendDt)
    if(columnId == "intendDt"){
        dlt_invoiceCommon.setCellData(0, "confirmDt", value);
        dlt_invoiceCommon.setCellData(0, "bilgIntendDt", value);
        dlt_purchaseCerti.setCellData(0, "pchsIntendDt", value);
    }

    //Customer INV  clntBilgDocNo
    if(columnId == "clntBilgDocNo"){
        dlt_invoiceCommon.setCellData(0, "clntBilgDocNo", value);
        dlt_purchaseCerti.setCellData(0, "clntBilgDocNo", value);
    }

    //PIC (bilgPicNo, Col=bilgPicNm
    if(columnId == "bilgPicNo"){
        dlt_invoiceCommon.setCellData(0, "bilgPicNo", value);
        dlt_purchaseCerti.setCellData(0, "pchsPicNo", value);
    }
    if(columnId == "bilgPicNm"){
        dlt_invoiceCommon.setCellData(0, "bilgPicNm", value);
        dlt_purchaseCerti.setCellData(0, "pchsPicNm", value);
    }

    //Remark (summary)
    if(columnId == "summary"){
        dlt_invoiceCommon.setCellData(0, "summary", value);
        dlt_purchaseCerti.setCellData(0, "rmk", value);
    }
};

scwin.dlt_partnerFreight_onrowpositionchange = function (info) {
    var row = info.newRowIndex;

    if(dlt_partnerInvoiceList.getCellData(dlt_partnerInvoiceList.getRowPosition(), "certiNo") == ""){
        gr_invoiceFreightList.setCellReadOnly(row, "chk", false);
    } else {
        gr_invoiceFreightList.setCellReadOnly(row, "chk", true);
    }
};

scwin.dlt_partnerFreight_ondataload = function () {
    var totCnt = dlt_partnerFreight.getRowCount();

    for(var row = 0; row < totCnt; row++) {

        if(dlt_partnerInvoiceList.getCellData(dlt_partnerInvoiceList.getRowPosition(), "certiNo") == ""){
            gr_invoiceFreightList.setCellReadOnly(row, "chk", false);
        } else {
            gr_invoiceFreightList.setCellReadOnly(row, "chk", true);
        }
    }

};
